package ir.tahamohamadi.skill; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="skill_category") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class SkillCategory extends AuditedSoftDeletableEntity { @Column(name="category_key",nullable=false) private String categoryKey; @Column(name="sort_order",nullable=false) private int sortOrder; @Column(name="is_active",nullable=false) private boolean active; private SkillCategory(UUID id,String key,int order,Instant at){initialize(id,at);categoryKey=requireNonBlank(key,"categoryKey");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");sortOrder=order;active=true;} public static SkillCategory create(UUID id,String key,int order,Instant at){return new SkillCategory(id,key,order,at);} public void update(String key,int order){categoryKey=requireNonBlank(key,"categoryKey");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");sortOrder=order;updatedAt=Instant.now();} public void activate(){active=true;updatedAt=Instant.now();} public void deactivate(){active=false;updatedAt=Instant.now();} }
